content = '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>NNIT Shop - Online Store</title>\n<link href="https://fonts.googleapis.com/css2?family=Playfair+Display:wght@700;900&family=DM+Sans:wght@300;400;500;600;700&family=JetBrains+Mono:wght@400;500&display=swap" rel="stylesheet">\n<style>\n:root{\n--bg:#fafaf8;--surface:#ffffff;--surface2:#f5f5f0;--border:#e8e4dc;\n--dark:#1a1a18;--dark2:#2d2d2a;--accent:#c8a96e;--accent2:#e8c87e;\n--red:#e85d4a;--green:#4a9e6b;--blue:#4a6ee8;\n--text:#1a1a18;--text2:#6b6b60;--text3:#a8a89a;\n--font:\'DM Sans\',sans-serif;--display:\'Playfair Display\',serif;--mono:\'JetBrains Mono\',monospace;\n}\n*{margin:0;padding:0;box-sizing:border-box;}\nbody{background:var(--bg);color:var(--text);font-family:var(--font);min-height:100vh;}\n\n/* TOPBAR */\n.announcement{background:var(--dark);color:var(--accent2);text-align:center;padding:8px;font-size:12px;font-family:var(--mono);letter-spacing:2px;}\n.topbar{background:var(--surface);border-bottom:1px solid var(--border);padding:0 40px;height:64px;display:flex;align-items:center;justify-content:space-between;position:sticky;top:0;z-index:200;}\n.logo{font-family:var(--display);font-size:22px;font-weight:900;color:var(--dark);letter-spacing:1px;cursor:pointer;}\n.logo span{color:var(--accent);}\n.nav{display:flex;gap:28px;align-items:center;}\n.nav-link{font-size:13px;font-weight:500;color:var(--text2);cursor:pointer;transition:color 0.15s;text-decoration:none;}\n.nav-link:hover,.nav-link.active{color:var(--dark);}\n.topbar-actions{display:flex;gap:12px;align-items:center;}\n.icon-btn{width:38px;height:38px;border-radius:50%;border:1px solid var(--border);background:var(--surface);cursor:pointer;display:flex;align-items:center;justify-content:center;font-size:14px;transition:all 0.15s;position:relative;}\n.icon-btn:hover{background:var(--dark);color:white;border-color:var(--dark);}\n.cart-count{position:absolute;top:-4px;right:-4px;background:var(--red);color:white;font-size:9px;width:16px;height:16px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-family:var(--mono);}\n.search-bar{display:flex;align-items:center;background:var(--surface2);border:1px solid var(--border);border-radius:24px;padding:0 16px;height:38px;gap:8px;min-width:240px;}\n.search-bar input{border:none;background:transparent;outline:none;font-size:13px;font-family:var(--font);color:var(--text);width:100%;}\n.search-bar input::placeholder{color:var(--text3);}\n\n/* HERO */\n.hero{background:var(--dark);color:white;padding:80px 40px;display:grid;grid-template-columns:1fr 1fr;gap:40px;align-items:center;min-height:520px;position:relative;overflow:hidden;}\n.hero::before{content:\'\';position:absolute;top:-100px;right:-100px;width:500px;height:500px;background:radial-gradient(circle,rgba(200,169,110,0.15) 0%,transparent 70%);}\n.hero-tag{display:inline-block;background:rgba(200,169,110,0.15);color:var(--accent2);border:1px solid rgba(200,169,110,0.3);padding:4px 14px;border-radius:20px;font-size:11px;font-family:var(--mono);letter-spacing:2px;margin-bottom:20px;}\n.hero-title{font-family:var(--display);font-size:58px;line-height:1.1;margin-bottom:16px;font-weight:900;}\n.hero-title span{color:var(--accent2);}\n.hero-sub{color:rgba(255,255,255,0.6);font-size:15px;line-height:1.7;margin-bottom:32px;max-width:440px;}\n.hero-btns{display:flex;gap:12px;flex-wrap:wrap;}\n.btn-primary{background:var(--accent);color:var(--dark);border:none;padding:12px 28px;border-radius:8px;font-size:14px;font-family:var(--font);font-weight:700;cursor:pointer;transition:all 0.15s;}\n.btn-primary:hover{background:var(--accent2);transform:translateY(-1px);}\n.btn-ghost{background:transparent;color:white;border:1px solid rgba(255,255,255,0.3);padding:12px 28px;border-radius:8px;font-size:14px;font-family:var(--font);font-weight:600;cursor:pointer;transition:all 0.15s;}\n.btn-ghost:hover{border-color:white;background:rgba(255,255,255,0.05);}\n.hero-img{background:linear-gradient(135deg,rgba(200,169,110,0.1),rgba(200,169,110,0.05));border:1px solid rgba(200,169,110,0.2);border-radius:16px;height:380px;display:flex;align-items:center;justify-content:center;font-size:100px;}\n.hero-stats{display:flex;gap:32px;margin-top:32px;}\n.hstat-num{font-family:var(--display);font-size:28px;color:var(--accent2);}\n.hstat-label{font-size:11px;color:rgba(255,255,255,0.4);font-family:var(--mono);}\n\n/* CATEGORIES */\n.section{padding:60px 40px;}\n.section-header{display:flex;justify-content:space-between;align-items:flex-end;margin-bottom:32px;}\n.section-title{font-family:var(--display);font-size:32px;font-weight:900;}\n.section-sub{color:var(--text2);font-size:13px;margin-top:4px;}\n.see-all{font-size:13px;color:var(--accent);font-weight:600;cursor:pointer;border:none;background:none;font-family:var(--font);}\n.cats-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:14px;}\n.cat-card{background:var(--surface);border:1px solid var(--border);border-radius:12px;padding:24px 16px;text-align:center;cursor:pointer;transition:all 0.2s;}\n.cat-card:hover{border-color:var(--accent);transform:translateY(-2px);box-shadow:0 8px 24px rgba(0,0,0,0.08);}\n.cat-icon{font-size:36px;margin-bottom:10px;display:block;}\n.cat-name{font-size:13px;font-weight:600;color:var(--text);}\n.cat-count{font-size:11px;color:var(--text3);font-family:var(--mono);margin-top:2px;}\n\n/* PRODUCTS */\n.products-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(240px,1fr));gap:20px;}\n.product-card{background:var(--surface);border:1px solid var(--border);border-radius:14px;overflow:hidden;cursor:pointer;transition:all 0.2s;position:relative;}\n.product-card:hover{box-shadow:0 12px 40px rgba(0,0,0,0.1);transform:translateY(-3px);}\n.product-img{height:220px;background:var(--surface2);display:flex;align-items:center;justify-content:center;font-size:64px;position:relative;overflow:hidden;}\n.product-badge{position:absolute;top:12px;left:12px;background:var(--red);color:white;font-size:10px;padding:3px 8px;border-radius:6px;font-family:var(--mono);font-weight:600;}\n.product-badge.new{background:var(--green);}\n.product-badge.hot{background:var(--accent);}\n.product-wish{position:absolute;top:12px;right:12px;width:32px;height:32px;background:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:14px;cursor:pointer;border:1px solid var(--border);transition:all 0.15s;}\n.product-wish:hover{background:var(--red);color:white;border-color:var(--red);}\n.product-wish.active{background:var(--red);color:white;border-color:var(--red);}\n.product-info{padding:16px;}\n.product-cat{font-size:10px;color:var(--text3);font-family:var(--mono);letter-spacing:1px;margin-bottom:4px;}\n.product-name{font-size:14px;font-weight:600;color:var(--text);margin-bottom:8px;line-height:1.4;}\n.product-rating{display:flex;align-items:center;gap:6px;margin-bottom:10px;}\n.stars{color:var(--accent);font-size:12px;}\n.rating-count{font-size:11px;color:var(--text3);font-family:var(--mono);}\n.product-price{display:flex;align-items:center;gap:8px;margin-bottom:12px;}\n.price-current{font-family:var(--display);font-size:20px;font-weight:700;color:var(--dark);}\n.price-old{font-size:13px;color:var(--text3);text-decoration:line-through;}\n.price-save{font-size:11px;color:var(--green);font-family:var(--mono);}\n.btn-cart{width:100%;background:var(--dark);color:white;border:none;padding:10px;border-radius:8px;font-size:13px;font-family:var(--font);font-weight:600;cursor:pointer;transition:all 0.15s;}\n.btn-cart:hover{background:var(--accent);color:var(--dark);}\n\n/* FILTERS */\n.filters{display:flex;gap:10px;flex-wrap:wrap;margin-bottom:24px;}\n.filter-btn{padding:7px 16px;border-radius:20px;border:1px solid var(--border);background:var(--surface);color:var(--text2);font-size:12px;cursor:pointer;transition:all 0.15s;font-family:var(--font);font-weight:500;}\n.filter-btn:hover,.filter-btn.active{background:var(--dark);color:white;border-color:var(--dark);}\n.sort-select{padding:7px 16px;border-radius:20px;border:1px solid var(--border);background:var(--surface);color:var(--text2);font-size:12px;cursor:pointer;font-family:var(--font);outline:none;margin-left:auto;}\n\n/* CART SIDEBAR */\n.cart-overlay{position:fixed;inset:0;background:rgba(0,0,0,0.5);z-index:300;backdrop-filter:blur(4px);}\n.cart-sidebar{position:fixed;right:0;top:0;bottom:0;width:420px;background:var(--surface);z-index:301;display:flex;flex-direction:column;box-shadow:-20px 0 60px rgba(0,0,0,0.15);}\n.cart-header{padding:24px;border-bottom:1px solid var(--border);display:flex;justify-content:space-between;align-items:center;}\n.cart-title{font-family:var(--display);font-size:20px;font-weight:700;}\n.close-btn{width:32px;height:32px;border-radius:50%;border:1px solid var(--border);background:none;cursor:pointer;font-size:16px;display:flex;align-items:center;justify-content:center;}\n.close-btn:hover{background:var(--dark);color:white;}\n.cart-items{flex:1;overflow-y:auto;padding:16px;}\n.cart-item{display:flex;gap:12px;padding:12px;background:var(--surface2);border-radius:10px;margin-bottom:10px;}\n.cart-item-img{width:64px;height:64px;background:var(--border);border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:28px;flex-shrink:0;}\n.cart-item-info{flex:1;}\n.cart-item-name{font-size:13px;font-weight:600;margin-bottom:4px;}\n.cart-item-price{font-size:14px;font-weight:700;color:var(--dark);}\n.cart-item-qty{display:flex;align-items:center;gap:8px;margin-top:8px;}\n.qty-btn{width:24px;height:24px;border-radius:6px;border:1px solid var(--border);background:var(--surface);cursor:pointer;font-size:14px;display:flex;align-items:center;justify-content:center;font-weight:700;}\n.qty-btn:hover{background:var(--dark);color:white;}\n.qty-val{font-size:13px;font-weight:600;min-width:20px;text-align:center;}\n.cart-footer{padding:20px;border-top:1px solid var(--border);}\n.cart-total{display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;}\n.cart-total-label{font-size:14px;color:var(--text2);}\n.cart-total-val{font-family:var(--display);font-size:24px;font-weight:700;}\n.btn-checkout{width:100%;background:var(--dark);color:white;border:none;padding:14px;border-radius:10px;font-size:15px;font-family:var(--font);font-weight:700;cursor:pointer;transition:all 0.15s;margin-bottom:8px;}\n.btn-checkout:hover{background:var(--accent);color:var(--dark);}\n.cart-empty{text-align:center;padding:60px 20px;}\n.cart-empty-icon{font-size:48px;margin-bottom:12px;}\n.cart-empty-title{font-family:var(--display);font-size:18px;margin-bottom:6px;}\n.cart-empty-sub{color:var(--text2);font-size:13px;}\n\n/* MODAL */\n.modal-overlay{position:fixed;inset:0;background:rgba(0,0,0,0.6);z-index:400;display:flex;align-items:center;justify-content:center;padding:20px;backdrop-filter:blur(6px);}\n.modal{background:var(--surface);border-radius:18px;width:760px;max-width:100%;max-height:90vh;overflow-y:auto;}\n.modal-body{display:grid;grid-template-columns:1fr 1fr;gap:0;}\n.modal-img{background:var(--surface2);border-radius:18px 0 0 18px;display:flex;align-items:center;justify-content:center;font-size:100px;min-height:400px;}\n.modal-info{padding:32px;}\n.modal-cat{font-size:11px;color:var(--text3);font-family:var(--mono);letter-spacing:2px;margin-bottom:8px;}\n.modal-title{font-family:var(--display);font-size:24px;font-weight:700;margin-bottom:12px;line-height:1.3;}\n.modal-price{font-family:var(--display);font-size:32px;font-weight:700;color:var(--dark);margin-bottom:16px;}\n.modal-desc{font-size:13px;color:var(--text2);line-height:1.8;margin-bottom:20px;}\n.modal-qty{display:flex;align-items:center;gap:12px;margin-bottom:20px;}\n.modal-qty-label{font-size:13px;font-weight:600;}\n.modal-actions{display:flex;flex-direction:column;gap:10px;}\n.btn-add-cart{background:var(--dark);color:white;border:none;padding:14px;border-radius:10px;font-size:14px;font-family:var(--font);font-weight:700;cursor:pointer;transition:all 0.15s;}\n.btn-add-cart:hover{background:var(--accent);color:var(--dark);}\n.modal-close{position:absolute;top:16px;right:16px;width:36px;height:36px;border-radius:50%;background:white;border:1px solid var(--border);cursor:pointer;font-size:16px;display:flex;align-items:center;justify-content:center;}\n\n/* BANNER */\n.banner{background:linear-gradient(135deg,var(--dark),var(--dark2));color:white;padding:48px 40px;border-radius:16px;margin:0 40px 40px;display:grid;grid-template-columns:1fr auto;gap:32px;align-items:center;}\n.banner-title{font-family:var(--display);font-size:28px;font-weight:900;margin-bottom:8px;}\n.banner-sub{color:rgba(255,255,255,0.6);font-size:14px;}\n.banner-input{display:flex;gap:8px;margin-top:16px;}\n.banner-input input{background:rgba(255,255,255,0.1);border:1px solid rgba(255,255,255,0.2);color:white;padding:10px 16px;border-radius:8px;font-size:13px;font-family:var(--font);outline:none;flex:1;}\n.banner-input input::placeholder{color:rgba(255,255,255,0.4);}\n.banner-input button{background:var(--accent);color:var(--dark);border:none;padding:10px 20px;border-radius:8px;font-size:13px;font-family:var(--font);font-weight:700;cursor:pointer;}\n\n/* TOAST */\n.toast{position:fixed;bottom:24px;right:24px;background:var(--dark);color:white;padding:12px 20px;border-radius:10px;font-size:13px;z-index:999;display:flex;align-items:center;gap:8px;box-shadow:0 8px 24px rgba(0,0,0,0.2);}\n.toast-icon{font-size:16px;}\n\n/* FOOTER */\n.footer{background:var(--dark);color:rgba(255,255,255,0.6);padding:48px 40px 24px;margin-top:40px;}\n.footer-grid{display:grid;grid-template-columns:2fr 1fr 1fr 1fr;gap:40px;margin-bottom:40px;}\n.footer-brand{font-family:var(--display);font-size:20px;color:white;margin-bottom:12px;}\n.footer-desc{font-size:13px;line-height:1.7;}\n.footer-title{font-size:12px;font-family:var(--mono);letter-spacing:2px;color:var(--accent2);margin-bottom:14px;}\n.footer-link{display:block;font-size:13px;color:rgba(255,255,255,0.5);margin-bottom:8px;cursor:pointer;transition:color 0.15s;}\n.footer-link:hover{color:white;}\n.footer-bottom{border-top:1px solid rgba(255,255,255,0.1);padding-top:20px;display:flex;justify-content:space-between;align-items:center;font-size:12px;}\n\n/* UTIL */\n.container{max-width:1280px;margin:0 auto;}\n@keyframes fadeIn{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:translateY(0)}}\n.fade-in{animation:fadeIn 0.3s ease}\n@keyframes slideIn{from{transform:translateX(100%)}to{transform:translateX(0)}}\n.slide-in{animation:slideIn 0.3s ease}\n</style>\n</head>\n<body>\n\n<!-- ANNOUNCEMENT -->\n<div class="announcement">FREE SHIPPING ON ORDERS OVER 50 EUR - USE CODE: NNIT10 FOR 10% OFF</div>\n\n<!-- TOPBAR -->\n<div class="topbar">\n  <div class="logo" onclick="showPage(\'home\')">NNIT<span>.</span>SHOP</div>\n  <nav class="nav">\n    <a class="nav-link active" onclick="showPage(\'home\')">Home</a>\n    <a class="nav-link" onclick="showPage(\'shop\')">Shop</a>\n    <a class="nav-link" onclick="filterCat(\'electronics\')">Electronics</a>\n    <a class="nav-link" onclick="filterCat(\'fashion\')">Fashion</a>\n    <a class="nav-link" onclick="filterCat(\'home\')">Home</a>\n    <a class="nav-link" onclick="showPage(\'about\')">About</a>\n  </nav>\n  <div class="topbar-actions">\n    <div class="search-bar">\n      <span>&#128269;</span>\n      <input type="text" id="search-input" placeholder="Search products..." onkeyup="handleSearch()" oninput="handleSearch()">\n    </div>\n    <div class="icon-btn" onclick="showWishlist()" title="Wishlist">[WISH]</div>\n    <div class="icon-btn" onclick="toggleCart()" title="Cart">\n      [CART]\n      <div class="cart-count" id="cart-count">0</div>\n    </div>\n    <div class="icon-btn" onclick="showPage(\'account\')" title="Account">&#128100;</div>\n  </div>\n</div>\n\n<!-- MAIN CONTENT -->\n<div id="main-content"></div>\n\n<!-- CART SIDEBAR -->\n<div class="cart-overlay" id="cart-overlay" style="display:none" onclick="toggleCart()"></div>\n<div class="cart-sidebar slide-in" id="cart-sidebar" style="display:none">\n  <div class="cart-header">\n    <div class="cart-title">Shopping Cart</div>\n    <button class="close-btn" onclick="toggleCart()">X</button>\n  </div>\n  <div class="cart-items" id="cart-items"></div>\n  <div class="cart-footer" id="cart-footer"></div>\n</div>\n\n<!-- PRODUCT MODAL -->\n<div class="modal-overlay" id="product-modal" style="display:none" onclick="if(event.target.id===\'product-modal\')closeModal()">\n  <div class="modal" style="position:relative">\n    <button class="modal-close" onclick="closeModal()">X</button>\n    <div id="modal-content"></div>\n  </div>\n</div>\n\n<script>\n// ===== DATA =====\nvar PRODUCTS = [\n  {id:1,name:"Wireless Noise-Cancelling Headphones",cat:"electronics",icon:"https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=400&h=400&fit=crop",price:89.99,oldPrice:129.99,rating:4.8,reviews:234,badge:"SALE",desc:"Premium wireless headphones with active noise cancellation. 30-hour battery life, comfortable over-ear design, crystal clear audio.",stock:15},\n  {id:2,name:"Smart Watch Pro Series",cat:"electronics",icon:"https://images.unsplash.com/photo-1523275335684-37898b6baf30?w=400&h=400&fit=crop",price:199.99,oldPrice:249.99,rating:4.7,reviews:189,badge:"HOT",desc:"Feature-packed smartwatch with health monitoring, GPS, and 7-day battery. Compatible with iOS and Android.",stock:8},\n  {id:3,name:"4K Action Camera",cat:"electronics",icon:"https://images.unsplash.com/photo-1502920917128-1aa500764cbd?w=400&h=400&fit=crop",price:149.99,oldPrice:199.99,rating:4.6,reviews:156,badge:"SALE",desc:"Waterproof 4K action camera with image stabilization. Perfect for sports and adventure filming.",stock:20},\n  {id:4,name:"Bluetooth Speaker",cat:"electronics",icon:"https://images.unsplash.com/photo-1608043152269-423dbba4e7e1?w=400&h=400&fit=crop",price:59.99,oldPrice:79.99,rating:4.5,reviews:312,badge:"",desc:"360-degree surround sound speaker. Waterproof IPX7, 24-hour playtime, built-in microphone.",stock:30},\n  {id:5,name:"Premium Leather Jacket",cat:"fashion",icon:"https://images.unsplash.com/photo-1551028719-00167b16eac5?w=400&h=400&fit=crop",price:179.99,oldPrice:229.99,rating:4.9,reviews:89,badge:"NEW",desc:"Genuine leather jacket with premium stitching. Available in black and brown. Classic style meets modern design.",stock:12},\n  {id:6,name:"Running Shoes Ultra",cat:"fashion",icon:"https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=400&h=400&fit=crop",price:119.99,oldPrice:159.99,rating:4.7,reviews:445,badge:"HOT",desc:"Lightweight running shoes with responsive cushioning. Breathable mesh upper, rubber outsole for maximum grip.",stock:25},\n  {id:7,name:"Designer Sunglasses",cat:"fashion",icon:"https://images.unsplash.com/photo-1560393464-5c69a73c5770?w=400&h=400&fit=crop",price:69.99,oldPrice:99.99,rating:4.6,reviews:167,badge:"SALE",desc:"UV400 protection polarized lenses. Lightweight frame, scratch-resistant coating. Comes with protective case.",stock:18},\n  {id:8,name:"Casual Cotton T-Shirt Pack",cat:"fashion",icon:"https://images.unsplash.com/photo-1511499767150-a48a237f0083?w=400&h=400&fit=crop",price:34.99,oldPrice:49.99,rating:4.4,reviews:523,badge:"",desc:"Pack of 3 premium cotton t-shirts. Soft, breathable fabric. Available in multiple colors and sizes.",stock:50},\n  {id:9,name:"Coffee Machine Deluxe",cat:"home",icon:"https://images.unsplash.com/photo-1495474472287-4d71bcdd2085?w=400&h=400&fit=crop",price:129.99,oldPrice:179.99,rating:4.8,reviews:201,badge:"HOT",desc:"Automatic coffee machine with built-in grinder. 15-bar pressure pump, milk frother, programmable timer.",stock:10},\n  {id:10,name:"Air Purifier HEPA",cat:"home",icon:"https://images.unsplash.com/photo-1560393464-5c69a73c5770?w=400&h=400&fit=crop",price:89.99,oldPrice:119.99,rating:4.7,reviews:134,badge:"NEW",desc:"True HEPA filter removes 99.97% of particles. Quiet operation, covers up to 50m2. Smart air quality indicator.",stock:14},\n  {id:11,name:"Yoga Mat Premium",cat:"sports",icon:"https://images.unsplash.com/photo-1601925228897-b7ed5e97c26b?w=400&h=400&fit=crop",price:44.99,oldPrice:59.99,rating:4.6,reviews:289,badge:"",desc:"Extra thick non-slip yoga mat. Eco-friendly material, carrying strap included. 6mm cushioning for joints.",stock:35},\n  {id:12,name:"Protein Shaker Bottle",cat:"sports",icon:"https://images.unsplash.com/photo-1593095948071-474c5cc2989d?w=400&h=400&fit=crop",price:19.99,oldPrice:29.99,rating:4.5,reviews:678,badge:"",desc:"BPA-free shaker bottle with wire whisk ball. 700ml capacity, leak-proof lid, dishwasher safe.",stock:100},\n  {id:13,name:"Skincare Gift Set",cat:"beauty",icon:"https://images.unsplash.com/photo-1556228578-8c89e6adf883?w=400&h=400&fit=crop",price:79.99,oldPrice:109.99,rating:4.8,reviews:145,badge:"NEW",desc:"Complete skincare routine set. Cleanser, toner, moisturizer and serum. Suitable for all skin types.",stock:22},\n  {id:14,name:"Electric Toothbrush",cat:"beauty",icon:"https://images.unsplash.com/photo-1607613009820-a29f7bb81c04?w=400&h=400&fit=crop",price:54.99,oldPrice:74.99,rating:4.7,reviews:367,badge:"SALE",desc:"Sonic electric toothbrush with 5 cleaning modes. 2-minute timer, 30-second pacer. 30-day battery life.",stock:28},\n  {id:15,name:"Kids Learning Tablet",cat:"kids",icon:"https://images.unsplash.com/photo-1585790050230-5dd28404ccb9?w=400&h=400&fit=crop",price:99.99,oldPrice:139.99,rating:4.8,reviews:256,badge:"HOT",desc:"Educational tablet for kids 3-12. Parental controls, 5000+ learning games. Drop-proof case included.",stock:16},\n  {id:16,name:"Board Game Collection",cat:"kids",icon:"https://images.unsplash.com/photo-1610890716171-6b1bb98ffd09?w=400&h=400&fit=crop",price:39.99,oldPrice:54.99,rating:4.9,reviews:178,badge:"NEW",desc:"Premium board game set with 10 classic games. Family fun for ages 4+. High quality materials.",stock:40},\n];\n\nvar CATEGORIES = [\n  {id:"all",name:"All Products",icon:"https://images.unsplash.com/photo-1560393464-5c69a73c5770?w=400&h=400&fit=crop",count:PRODUCTS.length},\n  {id:"electronics",name:"Electronics",icon:"TECH",count:PRODUCTS.filter(p=>p.cat==="electronics").length},\n  {id:"fashion",name:"Fashion",icon:"FASHION",count:PRODUCTS.filter(p=>p.cat==="fashion").length},\n  {id:"home",name:"Home & Living",icon:"HOME",count:PRODUCTS.filter(p=>p.cat==="home").length},\n  {id:"sports",name:"Sports",icon:"SPORTS",count:PRODUCTS.filter(p=>p.cat==="sports").length},\n  {id:"beauty",name:"Beauty",icon:"BEAUTY",count:PRODUCTS.filter(p=>p.cat==="beauty").length},\n  {id:"kids",name:"Kids & Toys",icon:"KIDS",count:PRODUCTS.filter(p=>p.cat==="kids").length},\n];\n\nvar cart = JSON.parse(localStorage.getItem("nnit_cart") || "[]");\nvar wishlist = JSON.parse(localStorage.getItem("nnit_wish") || "[]");\nvar currentCat = "all";\nvar currentSort = "featured";\nvar searchQuery = "";\nvar modalQty = 1;\n\n// ===== CART =====\nfunction saveCart(){localStorage.setItem("nnit_cart",JSON.stringify(cart));}\nfunction saveWish(){localStorage.setItem("nnit_wish",JSON.stringify(wishlist));}\n\nfunction getCartCount(){return cart.reduce(function(s,i){return s+i.qty;},0);}\nfunction getCartTotal(){return cart.reduce(function(s,i){return s+i.price*i.qty;},0);}\n\nfunction updateCartCount(){\n  var el = document.getElementById("cart-count");\n  if(el) el.textContent = getCartCount();\n}\n\nfunction addToCart(productId, qty){\n  qty = qty || 1;\n  var p = PRODUCTS.find(function(x){return x.id===productId;});\n  if(!p) return;\n  var existing = cart.find(function(x){return x.id===productId;});\n  if(existing) existing.qty += qty;\n  else cart.push({id:p.id, name:p.name, price:p.price, icon:p.icon, qty:qty});\n  saveCart();\n  updateCartCount();\n  showToast(p.icon + " Added to cart!");\n  renderCart();\n}\n\nfunction removeFromCart(productId){\n  cart = cart.filter(function(x){return x.id!==productId;});\n  saveCart();\n  updateCartCount();\n  renderCart();\n}\n\nfunction changeQty(productId, delta){\n  var item = cart.find(function(x){return x.id===productId;});\n  if(!item) return;\n  item.qty += delta;\n  if(item.qty <= 0) removeFromCart(productId);\n  else { saveCart(); renderCart(); }\n}\n\nfunction toggleWish(productId){\n  var idx = wishlist.indexOf(productId);\n  if(idx>=0) wishlist.splice(idx,1);\n  else wishlist.push(productId);\n  saveWish();\n}\n\nfunction isWished(productId){return wishlist.indexOf(productId)>=0;}\n\nfunction toggleCart(){\n  var overlay = document.getElementById("cart-overlay");\n  var sidebar = document.getElementById("cart-sidebar");\n  var shown = sidebar.style.display !== "none";\n  overlay.style.display = shown ? "none" : "block";\n  sidebar.style.display = shown ? "none" : "flex";\n  sidebar.style.flexDirection = "column";\n  if(!shown) renderCart();\n}\n\nfunction renderCart(){\n  var itemsEl = document.getElementById("cart-items");\n  var footerEl = document.getElementById("cart-footer");\n  if(!itemsEl) return;\n  if(!cart.length){\n    itemsEl.innerHTML = \'<div class="cart-empty"><div class="cart-empty-icon">ITEM</div><div class="cart-empty-title">Your cart is empty</div><div class="cart-empty-sub">Add some products to get started</div></div>\';\n    footerEl.innerHTML = "";\n    return;\n  }\n  itemsEl.innerHTML = cart.map(function(item){\n    return \'<div class="cart-item">\' +\n      \'<div class="cart-item-img"><img src="\'+item.icon+\'" style="width:64px;height:64px;object-fit:cover;border-radius:8px"></div>\' +\n      \'<div class="cart-item-info">\' +\n        \'<div class="cart-item-name">\'+item.name+\'</div>\' +\n        \'<div class="cart-item-price">EUR \'+item.price.toFixed(2)+\'</div>\' +\n        \'<div class="cart-item-qty">\' +\n          \'<button class="qty-btn" onclick="changeQty(\'+item.id+\',-1)">-</button>\' +\n          \'<span class="qty-val">\'+item.qty+\'</span>\' +\n          \'<button class="qty-btn" onclick="changeQty(\'+item.id+\',1)">+</button>\' +\n          \'<button onclick="removeFromCart(\'+item.id+\')" style="margin-left:8px;background:none;border:none;color:#e85d4a;cursor:pointer;font-size:12px">Remove</button>\' +\n        \'</div>\' +\n      \'</div>\' +\n    \'</div>\';\n  }).join("");\n  footerEl.innerHTML = \'<div class="cart-total"><span class="cart-total-label">Total</span><span class="cart-total-val">EUR \'+getCartTotal().toFixed(2)+\'</span></div>\' +\n    \'<button class="btn-checkout" onclick="checkout()">Checkout</button>\' +\n    \'<button onclick="toggleCart()" style="width:100%;background:none;border:1px solid var(--border);padding:12px;border-radius:10px;font-size:13px;font-family:var(--font);cursor:pointer;">Continue Shopping</button>\';\n}\n\nfunction checkout(){\n  showToast("Redirecting to checkout...");\n  setTimeout(function(){\n    alert("Checkout coming soon! Integrate with Stripe payment.");\n  }, 1000);\n}\n\n// ===== PRODUCTS =====\nfunction getFilteredProducts(){\n  var filtered = PRODUCTS.filter(function(p){\n    var catMatch = currentCat === "all" || p.cat === currentCat;\n    var searchMatch = !searchQuery || p.name.toLowerCase().indexOf(searchQuery.toLowerCase()) >= 0 || p.cat.toLowerCase().indexOf(searchQuery.toLowerCase()) >= 0;\n    return catMatch && searchMatch;\n  });\n  if(currentSort === "price-low") filtered.sort(function(a,b){return a.price-b.price;});\n  else if(currentSort === "price-high") filtered.sort(function(a,b){return b.price-a.price;});\n  else if(currentSort === "rating") filtered.sort(function(a,b){return b.rating-a.rating;});\n  else if(currentSort === "newest") filtered.sort(function(a,b){return b.id-a.id;});\n  return filtered;\n}\n\nfunction renderProductCard(p){\n  var discountPct = p.oldPrice ? Math.round((1-p.price/p.oldPrice)*100) : 0;\n  var wished = isWished(p.id);\n  return \'<div class="product-card" onclick="openModal(\'+p.id+\')">\' +\n    \'<div class="product-img"><img src="\'+p.icon+\'" style="width:100%;height:100%;object-fit:cover" onerror="this.style.display=\'none\'">\' +\n      (p.badge ? \'<div class="product-badge \'+(p.badge==="NEW"?"new":p.badge==="HOT"?"hot":"")+\'">\'+p.badge+\'</div>\' : \'\') +\n      \'<div class="product-wish\'+(wished?" active":"")+\'\\" onclick="event.stopPropagation();toggleWishUI(\'+p.id+\',this)">\'+( wished ? "?" : "?" )+\'</div>\' +\n    \'</div>\' +\n    \'<div class="product-info">\' +\n      \'<div class="product-cat">\'+p.cat.toUpperCase()+\'</div>\' +\n      \'<div class="product-name">\'+p.name+\'</div>\' +\n      \'<div class="product-rating"><span class="stars">\'+getStars(p.rating)+\'</span><span class="rating-count">(\'+p.reviews+\')</span></div>\' +\n      \'<div class="product-price">\' +\n        \'<span class="price-current">EUR \'+p.price.toFixed(2)+\'</span>\' +\n        (p.oldPrice ? \'<span class="price-old">EUR \'+p.oldPrice.toFixed(2)+\'</span>\' : \'\') +\n        (discountPct > 0 ? \'<span class="price-save">-\'+discountPct+\'%</span>\' : \'\') +\n      \'</div>\' +\n      \'<button class="btn-cart" onclick="event.stopPropagation();addToCart(\'+p.id+\')">Add to Cart</button>\' +\n    \'</div>\' +\n  \'</div>\';\n}\n\nfunction getStars(rating){\n  var full = Math.floor(rating);\n  var s = "";\n  for(var i=0;i<full;i++) s += "?";\n  if(rating % 1 >= 0.5) s += "?";\n  return s;\n}\n\nfunction toggleWishUI(productId, el){\n  toggleWish(productId);\n  var wished = isWished(productId);\n  el.textContent = wished ? "?" : "?";\n  el.classList.toggle("active", wished);\n}\n\n// ===== MODAL =====\nfunction openModal(productId){\n  var p = PRODUCTS.find(function(x){return x.id===productId;});\n  if(!p) return;\n  modalQty = 1;\n  var discountPct = p.oldPrice ? Math.round((1-p.price/p.oldPrice)*100) : 0;\n  document.getElementById("modal-content").innerHTML = \'<div class="modal-body">\' +\n    \'<div class="modal-img"><img src="\'+p.icon+\'" style="width:100%;height:100%;object-fit:cover;border-radius:18px 0 0 18px"></div>\' +\n    \'<div class="modal-info">\' +\n      \'<div class="modal-cat">\'+p.cat.toUpperCase()+\'</div>\' +\n      \'<div class="modal-title">\'+p.name+\'</div>\' +\n      \'<div style="display:flex;align-items:center;gap:12px;margin-bottom:12px">\' +\n        \'<span class="stars" style="font-size:16px">\'+getStars(p.rating)+\'</span>\' +\n        \'<span style="font-size:13px;color:var(--text3)">(\'+p.reviews+\' reviews)</span>\' +\n      \'</div>\' +\n      \'<div class="modal-price">EUR \'+p.price.toFixed(2)+\' \' +\n        (p.oldPrice ? \'<span style="font-size:16px;color:var(--text3);text-decoration:line-through;font-family:var(--font)">EUR \'+p.oldPrice.toFixed(2)+\'</span>\' : \'\') +\n        (discountPct > 0 ? \'<span style="font-size:14px;color:var(--green);font-family:var(--mono);margin-left:8px">-\'+discountPct+\'%</span>\' : \'\') +\n      \'</div>\' +\n      \'<div class="modal-desc">\'+p.desc+\'</div>\' +\n      \'<div style="font-size:12px;color:var(--green);font-family:var(--mono);margin-bottom:16px">? IN STOCK (\'+p.stock+\' available)</div>\' +\n      \'<div class="modal-qty">\' +\n        \'<span class="modal-qty-label">Quantity:</span>\' +\n        \'<button class="qty-btn" onclick="changeModalQty(-1)">-</button>\' +\n        \'<span class="qty-val" id="modal-qty-val">1</span>\' +\n        \'<button class="qty-btn" onclick="changeModalQty(1)">+</button>\' +\n      \'</div>\' +\n      \'<div class="modal-actions">\' +\n        \'<button class="btn-add-cart" onclick="addToCart(\'+p.id+\',modalQty)">Add to Cart</button>\' +\n        \'<button onclick="toggleWish(\'+p.id+\');showToast(\\\'Added to wishlist\\\')" style="width:100%;background:none;border:1px solid var(--border);padding:12px;border-radius:10px;font-size:14px;font-family:var(--font);cursor:pointer;">? Add to Wishlist</button>\' +\n      \'</div>\' +\n    \'</div>\' +\n  \'</div>\';\n  document.getElementById("product-modal").style.display = "flex";\n}\n\nfunction changeModalQty(d){\n  modalQty = Math.max(1, modalQty + d);\n  var el = document.getElementById("modal-qty-val");\n  if(el) el.textContent = modalQty;\n}\n\nfunction closeModal(){\n  document.getElementById("product-modal").style.display = "none";\n}\n\n// ===== PAGES =====\nfunction showPage(page){\n  document.querySelectorAll(".nav-link").forEach(function(e){e.classList.remove("active");});\n  if(page === "home") renderHome();\n  else if(page === "shop") renderShop();\n  else if(page === "about") renderAbout();\n  else if(page === "account") renderAccount();\n  else renderHome();\n}\n\nfunction filterCat(cat){\n  currentCat = cat;\n  searchQuery = "";\n  document.getElementById("search-input").value = "";\n  renderShop();\n}\n\nfunction handleSearch(){\n  searchQuery = document.getElementById("search-input").value;\n  if(searchQuery.length > 0) renderShop();\n}\n\nfunction renderHome(){\n  var featured = PRODUCTS.filter(function(p){return p.badge === "HOT" || p.badge === "NEW";}).slice(0,4);\n  var bestsellers = PRODUCTS.sort(function(a,b){return b.reviews-a.reviews;}).slice(0,4);\n  document.getElementById("main-content").innerHTML =\n  \'<div class="hero">\' +\n    \'<div>\' +\n      \'<div class="hero-tag">NEW ARRIVALS 2026</div>\' +\n      \'<div class="hero-title">Shop The<br>Best <span>Deals</span><br>Online</div>\' +\n      \'<div class="hero-sub">Discover thousands of products from top brands. Free shipping on orders over EUR 50.</div>\' +\n      \'<div class="hero-btns">\' +\n        \'<button class="btn-primary" onclick="showPage(\\\'shop\\\')">Shop Now</button>\' +\n        \'<button class="btn-ghost" onclick="filterCat(\\\'electronics\\\')">View Electronics</button>\' +\n      \'</div>\' +\n      \'<div class="hero-stats">\' +\n        \'<div><div class="hstat-num">\'+PRODUCTS.length+\'+</div><div class="hstat-label">PRODUCTS</div></div>\' +\n        \'<div><div class="hstat-num">99%</div><div class="hstat-label">SATISFACTION</div></div>\' +\n        \'<div><div class="hstat-num">24H</div><div class="hstat-label">DELIVERY</div></div>\' +\n      \'</div>\' +\n    \'</div>\' +\n    \'<div class="hero-img">??</div>\' +\n  \'</div>\' +\n\n  \'<div class="section">\' +\n    \'<div class="section-header"><div><div class="section-title">Shop by Category</div><div class="section-sub">Find what you are looking for</div></div><button class="see-all" onclick="showPage(\\\'shop\\\')">See All</button></div>\' +\n    \'<div class="cats-grid">\' +\n      CATEGORIES.map(function(c){\n        return \'<div class="cat-card" onclick="filterCat(\\\'\'+c.id+\'\\\')">\' +\n          \'<span class="cat-icon">\'+c.icon+\'</span>\' +\n          \'<div class="cat-name">\'+c.name+\'</div>\' +\n          \'<div class="cat-count">\'+c.count+\' items</div>\' +\n        \'</div>\';\n      }).join("") +\n    \'</div>\' +\n  \'</div>\' +\n\n  \'<div class="section" style="background:var(--surface2);padding-top:40px;padding-bottom:40px">\' +\n    \'<div class="section-header"><div><div class="section-title">Featured Products</div><div class="section-sub">Hand-picked for you</div></div><button class="see-all" onclick="showPage(\\\'shop\\\')">View All</button></div>\' +\n    \'<div class="products-grid">\' + featured.map(renderProductCard).join("") + \'</div>\' +\n  \'</div>\' +\n\n  \'<div class="banner">\' +\n    \'<div>\' +\n      \'<div class="banner-title">Get 10% Off Your First Order</div>\' +\n      \'<div class="banner-sub">Subscribe to our newsletter and receive exclusive deals</div>\' +\n      \'<div class="banner-input">\' +\n        \'<input type="email" placeholder="Enter your email address">\' +\n        \'<button onclick="showToast(\\\'Subscribed! Check your email.\\\')">Subscribe</button>\' +\n      \'</div>\' +\n    \'</div>\' +\n    \'<div style="font-size:80px">ITEM</div>\' +\n  \'</div>\' +\n\n  \'<div class="section">\' +\n    \'<div class="section-header"><div><div class="section-title">Best Sellers</div><div class="section-sub">Most popular products</div></div><button class="see-all" onclick="showPage(\\\'shop\\\')">View All</button></div>\' +\n    \'<div class="products-grid">\' + bestsellers.map(renderProductCard).join("") + \'</div>\' +\n  \'</div>\' +\n\n  renderFooter();\n}\n\nfunction renderShop(){\n  var filtered = getFilteredProducts();\n  document.getElementById("main-content").innerHTML =\n  \'<div class="section">\' +\n    \'<div class="section-header">\' +\n      \'<div><div class="section-title">\'+(currentCat==="all"?"All Products":CATEGORIES.find(function(c){return c.id===currentCat;})?.name||currentCat)+\'</div>\' +\n      \'<div class="section-sub">\'+filtered.length+\' products found</div></div>\' +\n    \'</div>\' +\n    \'<div class="filters">\' +\n      CATEGORIES.map(function(c){\n        return \'<button class="filter-btn\'+(currentCat===c.id?" active":"")+\'\\" onclick="currentCat=\\\'\'+c.id+\'\\\';renderShop()">\'+c.icon+\' \'+c.name+\'</button>\';\n      }).join("") +\n      \'<select class="sort-select" onchange="currentSort=this.value;renderShop()">\' +\n        \'<option value="featured">Featured</option>\' +\n        \'<option value="price-low">Price: Low to High</option>\' +\n        \'<option value="price-high">Price: High to Low</option>\' +\n        \'<option value="rating">Top Rated</option>\' +\n        \'<option value="newest">Newest</option>\' +\n      \'</select>\' +\n    \'</div>\' +\n    \'<div class="products-grid">\' +\n      (filtered.length ? filtered.map(renderProductCard).join("") : \'<div style="text-align:center;padding:60px;grid-column:1/-1"><div style="font-family:var(--display);font-size:24px;margin-bottom:8px">No products found</div><div style="color:var(--text2)">Try a different search or category</div></div>\') +\n    \'</div>\' +\n  \'</div>\' +\n  renderFooter();\n}\n\nfunction renderAbout(){\n  document.getElementById("main-content").innerHTML =\n  \'<div class="section" style="max-width:760px;margin:0 auto">\' +\n    \'<div class="section-title" style="margin-bottom:20px">About NNIT Shop</div>\' +\n    \'<p style="font-size:15px;color:var(--text2);line-height:1.9;margin-bottom:16px">NNIT Shop is your one-stop destination for quality products at competitive prices. We offer a wide range of electronics, fashion, home goods, sports equipment, beauty products and more.</p>\' +\n    \'<p style="font-size:15px;color:var(--text2);line-height:1.9;margin-bottom:32px">Our mission is to make online shopping easy, affordable and enjoyable for everyone. We ship to over 50 countries and offer 30-day returns on all products.</p>\' +\n    \'<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:20px">\' +\n      \'<div style="background:var(--surface2);border-radius:12px;padding:24px;text-align:center"><div style="font-size:36px;margin-bottom:8px">ITEM</div><div style="font-weight:600;margin-bottom:4px">Fast Shipping</div><div style="font-size:13px;color:var(--text2)">Delivered in 24-48 hours</div></div>\' +\n      \'<div style="background:var(--surface2);border-radius:12px;padding:24px;text-align:center"><div style="font-size:36px;margin-bottom:8px">ITEM</div><div style="font-weight:600;margin-bottom:4px">Secure Payments</div><div style="font-size:13px;color:var(--text2)">100% secure checkout</div></div>\' +\n      \'<div style="background:var(--surface2);border-radius:12px;padding:24px;text-align:center"><div style="font-size:36px;margin-bottom:8px">??</div><div style="font-weight:600;margin-bottom:4px">Easy Returns</div><div style="font-size:13px;color:var(--text2)">30-day return policy</div></div>\' +\n    \'</div>\' +\n  \'</div>\' +\n  renderFooter();\n}\n\nfunction renderAccount(){\n  document.getElementById("main-content").innerHTML =\n  \'<div class="section" style="max-width:500px;margin:0 auto">\' +\n    \'<div class="section-title" style="margin-bottom:24px">My Account</div>\' +\n    \'<div style="background:var(--surface2);border-radius:14px;padding:28px;margin-bottom:16px">\' +\n      \'<div style="font-weight:600;margin-bottom:16px">Sign In</div>\' +\n      \'<div style="margin-bottom:12px"><label style="font-size:12px;color:var(--text2);display:block;margin-bottom:4px">EMAIL</label><input type="email" placeholder="your@email.com" style="width:100%;background:var(--surface);border:1px solid var(--border);padding:10px 14px;border-radius:8px;font-size:14px;outline:none;font-family:var(--font)"></div>\' +\n      \'<div style="margin-bottom:16px"><label style="font-size:12px;color:var(--text2);display:block;margin-bottom:4px">PASSWORD</label><input type="password" placeholder="Password" style="width:100%;background:var(--surface);border:1px solid var(--border);padding:10px 14px;border-radius:8px;font-size:14px;outline:none;font-family:var(--font)"></div>\' +\n      \'<button onclick="showToast(\\\'Login coming soon!\\\')" style="width:100%;background:var(--dark);color:white;border:none;padding:12px;border-radius:8px;font-size:14px;font-family:var(--font);font-weight:700;cursor:pointer">Sign In</button>\' +\n    \'</div>\' +\n    \'<div style="text-align:center;font-size:13px;color:var(--text2)">Do not have an account? <span onclick="showToast(\\\'Registration coming soon!\\\')" style="color:var(--accent);cursor:pointer;font-weight:600">Register</span></div>\' +\n    \'<div style="background:var(--surface2);border-radius:14px;padding:20px;margin-top:20px">\' +\n      \'<div style="font-weight:600;margin-bottom:12px">Wishlist (\'+wishlist.length+\' items)</div>\' +\n      (wishlist.length ? wishlist.map(function(id){var p=PRODUCTS.find(function(x){return x.id===id;});return p?\'<div style="display:flex;gap:10px;align-items:center;padding:8px 0;border-bottom:1px solid var(--border)"><span style="font-size:24px">\'+p.icon+\'</span><div style="flex:1"><div style="font-size:13px;font-weight:600">\'+p.name+\'</div><div style="font-size:12px;color:var(--text2)">EUR \'+p.price.toFixed(2)+\'</div></div><button onclick="addToCart(\'+p.id+\')" style="background:var(--dark);color:white;border:none;padding:6px 12px;border-radius:6px;font-size:12px;cursor:pointer">Add to Cart</button></div>\':"";}).join("") : \'<div style="color:var(--text2);font-size:13px">No items in wishlist yet</div>\') +\n    \'</div>\' +\n  \'</div>\' +\n  renderFooter();\n}\n\nfunction showWishlist(){showPage("account");}\n\nfunction renderFooter(){\n  return \'<footer class="footer">\' +\n    \'<div class="footer-grid">\' +\n      \'<div><div class="footer-brand">NNIT.SHOP</div><div class="footer-desc">Your trusted online marketplace. Quality products, competitive prices, fast delivery.</div></div>\' +\n      \'<div><div class="footer-title">SHOP</div><span class="footer-link" onclick="filterCat(\\\'electronics\\\')">Electronics</span><span class="footer-link" onclick="filterCat(\\\'fashion\\\')">Fashion</span><span class="footer-link" onclick="filterCat(\\\'home\\\')">Home</span><span class="footer-link" onclick="filterCat(\\\'sports\\\')">Sports</span></div>\' +\n      \'<div><div class="footer-title">HELP</div><span class="footer-link">Shipping Info</span><span class="footer-link">Returns</span><span class="footer-link">FAQ</span><span class="footer-link">Contact</span></div>\' +\n      \'<div><div class="footer-title">COMPANY</div><span class="footer-link" onclick="showPage(\\\'about\\\')">About Us</span><span class="footer-link">Blog</span><span class="footer-link">Careers</span><span class="footer-link">Privacy</span></div>\' +\n    \'</div>\' +\n    \'<div class="footer-bottom"><span>2026 NNIT Shop. All rights reserved.</span><span>Powered by NNIT Technology</span></div>\' +\n  \'</footer>\';\n}\n\n// ===== TOAST =====\nfunction showToast(msg){\n  var existing = document.querySelector(".toast");\n  if(existing) existing.remove();\n  var t = document.createElement("div");\n  t.className = "toast";\n  t.innerHTML = \'<span class="toast-icon">ITEM</span>\' + msg;\n  document.body.appendChild(t);\n  setTimeout(function(){t.remove();},3000);\n}\n\n// ===== INIT =====\nupdateCartCount();\nrenderHome();\n</script>\n</body>\n</html>\n'
